public static Locale toLocale(final String str) {
    if (str == null) {
        return null;
    }
    final int len = str.length();
    if (len < 2) {
        throw new IllegalArgumentException("Invalid locale format: " + str);
    }

    // Handle the case where the locale string starts with an underscore (country only)
    if (str.charAt(0) == '_') {
        if (len < 3) {
            throw new IllegalArgumentException("Invalid locale format: " + str);
        }
        final char ch1 = str.charAt(1);
        final char ch2 = str.charAt(2);

        // Country codes should be uppercase letters
        if (!Character.isUpperCase(ch1) || !Character.isUpperCase(ch2)) {
            throw new IllegalArgumentException("Invalid locale format: " + str);
        }

        if (len == 3) {
            // Format: _XX (country only)
            return new Locale("", str.substring(1, 3));
        }

        // Check for variant part
        if (len >= 5 && str.charAt(3) == '_') {
            // Format: _XX_yyy (country + variant)
            return new Locale("", str.substring(1, 3), str.substring(4));
        } else if (len >= 4) {
            throw new IllegalArgumentException("Invalid locale format: " + str);
        } else {
            throw new IllegalArgumentException("Invalid locale format: " + str);
        }
    }

    // Original logic for language-based locales
